@startuml
!theme plain
skinparam packageStyle rectangle
skinparam sequenceMessageSize 100

package "Executor" as Executor1 {
  Executor1
}

package "Reactor" as Reactor1 {
  Reactor1
}

package "Executor" as Executor2 {
  Executor2
}

package "Reactor" as Reactor2 {
  Reactor2
}

Executor1 --> Reactor1 : 当前类型为pending
Reactor1 --> Executor2 : 执行对于的wake方法将Future的状态变为就绪（Ready）
Executor2 --> Reactor2 : 轮询其他future

@enduml
